 1→import chalk from "chalk";
 2→import { config, ensureRuntimeDirectories } from "./config.js";
 3→import { logger } from "./logger.js";
 4→import { createTools } from "./tools/index.js";
 5→import { GradeService } from "./services/grade-service.js";
 6→import { GradeAgent } from "./agent/grade-agent.js";
 7→import { WhatsAppHandler } from "./whatsapp/handler.js";
 8→
 9→async function bootstrap() {
10→  ensureRuntimeDirectories();
11→  logger.info(
12→    `${config.app.name} starting. Data directory: ${config.paths.data} | Model: ${config.ollama.model}`,
13→  );
14→  logger.info(
15→    `Single-number mode=${config.app.singleNumberMode} | loopGuard ttl=${config.loopGuard.processedMessageTtlMs}ms idTtl=${config.loopGuard.botMessageIdTtlMs}ms textTtl=${config.loopGuard.botMessageTextTtlMs}ms`,
16→  );
17→  logger.info(
18→    `Reply routing strategy=${config.replyRouting.strategy} fallback=${config.replyRouting.enableFallback} verifyTimeout=${config.replyRouting.verifyTimeoutMs}ms`,
19→  );
20→  process.stdout.write(
21→    chalk.green(
22→      `${config.app.name} is booting. Scan QR code in terminal once WhatsApp starts.\n`,
23→    ),
24→  );
25→
26→  const tools = createTools({ config, logger });
27→  const gradeService = new GradeService({
28→    config,
29→    logger,
30→    excelTool: tools.excel,
31→    pythonBridge: tools.pythonBridge,
32→  });
33→  const agent = new GradeAgent({ config, logger, tools, gradeService });
34→  const whatsapp = new WhatsAppHandler({ config, logger, agent });
35→
36→  await whatsapp.start();
37→
38→  process.on("SIGINT", () => {
39→    logger.info("Shutting down on SIGINT.");
40→    process.exit(0);
41→  });
42→  process.on("SIGTERM", () => {
43→    logger.info("Shutting down on SIGTERM.");
44→    process.exit(0);
45→  });
46→}
47→
48→bootstrap().catch((error) => {
49→  logger.error(`Fatal startup error: ${error.stack || error.message}`);
50→  process.exit(1);
51→});
