  1→import fs from "fs/promises";
  2→import path from "path";
  3→import crypto from "crypto";
  4→import mime from "mime-types";
  5→import pino from "pino";
  6→import qrcode from "qrcode-terminal";
  7→import makeWASocket, {
  8→  DisconnectReason,
  9→  downloadMediaMessage,
 10→  fetchLatestBaileysVersion,
 11→  useMultiFileAuthState,
 12→} from "@whiskeysockets/baileys";
 13→import { compactTimestamp } from "../tools/common.js";
 14→import {
 15→  makeInboundReplyKey,
 16→  makeReplyContentKey,
 17→  resolveReplyTargets,
 18→  sleep,
 19→} from "./reply-router.js";
 20→
 21→function unwrapMessageContainer(message) {
 22→  if (!message) return null;
 23→  if (message.ephemeralMessage?.message) {
 24→    return message.ephemeralMessage.message;
 25→  }
 26→  if (message.viewOnceMessage?.message) {
 27→    return message.viewOnceMessage.message;
 28→  }
 29→  return message;
 30→}
 31→
 32→function extractTextContent(message) {
 33→  const m = unwrapMessageContainer(message);
 34→  if (!m) return "";
 35→  if (m.conversation) return m.conversation;
 36→  if (m.extendedTextMessage?.text) return m.extendedTextMessage.text;
 37→  if (m.imageMessage?.caption) return m.imageMessage.caption;
 38→  if (m.documentMessage?.caption) return m.documentMessage.caption;
 39→  if (m.videoMessage?.caption) return m.videoMessage.caption;
 40→  return "";
 41→}
 42→
 43→function makeFileNameFromMime(messageId, contentType, mediaMime) {
 44→  const extFromMime = mime.extension(mediaMime || "") || null;
 45→  const ext = extFromMime || (contentType === "image" ? "jpg" : "bin");
 46→  return `${compactTimestamp()}_${messageId}.${ext}`;
 47→}
 48→
 49→function normalizeText(text) {
 50→  return String(text || "")
 51→    .trim()
 52→    .replace(/\s+/g, " ")
 53→    .toLowerCase();
 54→}
 55→
 56→function makeChatMessageKey(chatJid, messageId) {
 57→  return `${chatJid || "unknown"}:${messageId || "unknown"}`;
 58→}
 59→
 60→function makeTextFingerprint(chatJid, text) {
 61→  const normalized = normalizeText(text);
 62→  if (!normalized) return null;
 63→  return crypto
 64→    .createHash("sha256")
 65→    .update(`${chatJid || "unknown"}|${normalized}`)
 66→    .digest("hex");
 67→}
 68→
 69→function withTimeout(promise, ms, label = "operation") {
 70→  let timer = null;
 71→  return Promise.race([
 72→    promise,
 73→    new Promise((_, reject) => {
 74→      timer = setTimeout(() => {
 75→        reject(new Error(`${label} timed out after ${ms}ms`));
 76→      }, ms);
 77→    }),
 78→  ]).finally(() => {
 79→    if (timer) clearTimeout(timer);
 80→  });
 81→}
 82→
 83→function textPreview(text, maxLength = 80) {
 84→  const clean = String(text || "").replace(/\s+/g, " ").trim();
 85→  if (!clean) return "(empty)";
 86→  return clean.length <= maxLength ? clean : `${clean.slice(0, maxLength)}...`;
 87→}
 88→
 89→export class WhatsAppHandler {
 90→  constructor({ config, logger, agent }) {
 91→    this.config = config;
 92→    this.logger = logger;
 93→    this.agent = agent;
 94→    this.socket = null;
 95→    this.reconnectInProgress = false;
 96→    this.processedMessageCache = new Map();
 97→    this.botMessageIdCache = new Map();
 98→    this.botMessageTextCache = new Map();
 99→    this.outboundEchoObservedCache = new Map();
100→    this.inboundReplyCompletedCache = new Map();
101→    this.outboundContentPerInboundCache = new Map();
102→    this.chatQueues = new Map();
103→  }
104→
105→  async start() {
106→    await this.connect();
107→  }
108→
109→  async connect() {
110→    if (this.reconnectInProgress) return;
111→    this.reconnectInProgress = true;
112→    try {
113→      const { state, saveCreds } = await useMultiFileAuthState(
114→        this.config.paths.waSession,
115→      );
116→      const { version } = await fetchLatestBaileysVersion();
117→      this.socket = makeWASocket({
118→        version,
119→        auth: state,
120→        browser: ["Teacher GradeBot", "Terminal", "1.0.0"],
121→        logger: pino({ level: "silent" }),
122→        syncFullHistory: false,
123→      });
124→
125→      this.socket.ev.on("creds.update", saveCreds);
126→      this.socket.ev.on("connection.update", async (update) => {
127→        const { connection, lastDisconnect, qr } = update;
128→        if (qr) {
129→          this.logger.info("New WhatsApp QR received. Scan it with WhatsApp.");
130→          qrcode.generate(qr, { small: true });
131→        }
132→        if (connection === "open") {
133→          const meId = this.socket?.user?.id || "unknown";
134→          const meLid = this.socket?.user?.lid || "unknown";
135→          this.logger.info(`WhatsApp connected. meId=${meId} meLid=${meLid}`);
136→        } else if (connection === "close") {
137→          const statusCode =
138→            lastDisconnect?.error?.output?.statusCode ||
139→            lastDisconnect?.error?.statusCode;
140→          const shouldReconnect =
141→            statusCode !== DisconnectReason.loggedOut &&
142→            statusCode !== 401 &&
143→            statusCode !== 403;
144→          this.logger.warn(
145→            `WhatsApp disconnected. status=${statusCode || "unknown"} reconnect=${shouldReconnect}`,
146→          );
147→          if (shouldReconnect) {
148→            setTimeout(() => {
149→              this.connect().catch((error) => {
150→                this.logger.error(`Reconnect failed: ${error.message}`);
151→              });
152→            }, 2000);
153→          } else {
154→            this.logger.error(
155→              "Session logged out. Delete data/wa-session and restart for a new QR login.",
156→            );
157→          }
158→        }
159→      });
160→
161→      this.socket.ev.on("messages.upsert", async (upsert) => {
162→        const messageCount = (upsert.messages || []).length;
163→        this.logger.info(
164→          `messages.upsert received: type=${upsert.type} count=${messageCount}`,
165→        );
166→        if (!["notify", "append"].includes(upsert.type)) return;
167→        const tasks = [];
168→        for (const msg of upsert.messages || []) {
169→          if (this.observeOutgoingEchoFromUpsert(msg)) {
170→            continue;
171→          }
172→          tasks.push(
173→            this.enqueueByChat(msg?.key?.remoteJid, () =>
174→              this.handleIncomingMessage(msg),
175→            ),
176→          );
177→        }
178→        await Promise.allSettled(tasks);
179→      });
180→    } finally {
181→      this.reconnectInProgress = false;
182→    }
183→  }
184→
185→  enqueueByChat(chatJid, handler) {
186→    const key = chatJid || "unknown";
187→    const prior = this.chatQueues.get(key) || Promise.resolve();
188→    const next = prior
189→      .catch(() => undefined)
190→      .then(handler)
191→      .catch((error) => {
192→        this.logger.error(
193→          `Chat queue handler failed for ${key}: ${error.message || error}`,
194→        );
195→      })
196→      .finally(() => {
197→        if (this.chatQueues.get(key) === next) {
198→          this.chatQueues.delete(key);
199→        }
200→      });
201→    this.chatQueues.set(key, next);
202→    return next;
203→  }
204→
205→  observeOutgoingEchoFromUpsert(baileysMsg) {
206→    const chatJid = baileysMsg?.key?.remoteJid;
207→    const messageId = baileysMsg?.key?.id;
208→    if (!baileysMsg?.key?.fromMe || !chatJid || !messageId) {
209→      return false;
210→    }
211→
212→    const key = makeChatMessageKey(chatJid, messageId);
213→    if (!this.cacheHas(this.botMessageIdCache, key)) {
214→      return false;
215→    }
216→
217→    this.markOutboundEchoObserved(chatJid, messageId);
218→    this.logger.info(
219→      `Observed outbound echo immediately from upsert. outId=${messageId} chat=${chatJid}.`,
220→    );
221→    return true;
222→  }
223→
224→  pruneExpiredEntries(cache) {
225→    const now = Date.now();
226→    for (const [key, expiresAt] of cache.entries()) {
227→      if (!Number.isFinite(expiresAt) || expiresAt <= now) {
228→        cache.delete(key);
229→      }
230→    }
231→    const maxEntries = this.config.loopGuard.maxCacheEntries;
232→    if (cache.size <= maxEntries) return;
233→    const overflow = cache.size - maxEntries;
234→    let removed = 0;
235→    for (const key of cache.keys()) {
236→      cache.delete(key);
237→      removed += 1;
238→      if (removed >= overflow) break;
239→    }
240→  }
241→
242→  cacheSet(cache, key, ttlMs) {
243→    if (!key) return;
244→    const expiresAt = Date.now() + Math.max(1000, Number(ttlMs) || 1000);
245→    cache.set(key, expiresAt);
246→    this.pruneExpiredEntries(cache);
247→  }
248→
249→  cacheHas(cache, key) {
250→    if (!key) return false;
251→    const expiresAt = cache.get(key);
252→    if (!expiresAt) return false;
253→    if (expiresAt <= Date.now()) {
254→      cache.delete(key);
255→      return false;
256→    }
257→    return true;
258→  }
259→
260→  markOutboundEchoObserved(chatJid, messageId) {
261→    if (!chatJid || !messageId) return;
262→    this.cacheSet(
263→      this.outboundEchoObservedCache,
264→      makeChatMessageKey(chatJid, messageId),
265→      this.config.loopGuard.botMessageIdTtlMs,
266→    );
267→  }
268→
269→  hasOutboundEchoObserved(chatJid, messageId) {
270→    if (!chatJid || !messageId) return false;
271→    return this.cacheHas(
272→      this.outboundEchoObservedCache,
273→      makeChatMessageKey(chatJid, messageId),
274→    );
275→  }
276→
277→  hasInboundReplyCompleted(inboundKey) {
278→    return this.cacheHas(this.inboundReplyCompletedCache, inboundKey);
279→  }
280→
281→  markInboundReplyCompleted(inboundKey) {
282→    this.cacheSet(
283→      this.inboundReplyCompletedCache,
284→      inboundKey,
285→      this.config.loopGuard.processedMessageTtlMs,
286→    );
287→  }
288→
289→  async waitForDeliveryEvidence(chatJid, outboundMessageId) {
290→    if (!chatJid || !outboundMessageId) return false;
291→
292→    const timeoutMs = Math.max(0, this.config.replyRouting.verifyTimeoutMs || 0);
293→    if (this.hasOutboundEchoObserved(chatJid, outboundMessageId)) {
294→      return true;
295→    }
296→    if (timeoutMs <= 0) return false;
297→
298→    const deadline = Date.now() + timeoutMs;
299→    while (Date.now() < deadline) {
300→      if (this.hasOutboundEchoObserved(chatJid, outboundMessageId)) {
301→        return true;
302→      }
303→      await sleep(100);
304→    }
305→    return this.hasOutboundEchoObserved(chatJid, outboundMessageId);
306→  }
307→
308→  async sendReplyToTarget({ inboundKey, inboundMessageId, targetJid, replyText }) {
309→    const textHash = makeTextFingerprint(targetJid, replyText);
310→    const contentKey = makeReplyContentKey(inboundKey, targetJid, textHash);
311→    if (this.cacheHas(this.outboundContentPerInboundCache, contentKey)) {
312→      this.logger.info(
313→        `Reply dedupe skipped for inId=${inboundMessageId} target=${targetJid}.`,
314→      );
315→      return { skipped: true, targetJid };
316→    }
317→
318→    const sendResult = await this.socket.sendMessage(targetJid, { text: replyText });
319→    const outboundId = sendResult?.key?.id || "";
320→    this.rememberBotOutgoingMessage(targetJid, outboundId, replyText);
321→    this.cacheSet(
322→      this.outboundContentPerInboundCache,
323→      contentKey,
324→      this.config.loopGuard.processedMessageTtlMs,
325→    );
326→
327→    this.logger.info(
328→      `Reply send attempt success inId=${inboundMessageId} outId=${outboundId || "unknown"} target=${targetJid}.`,
329→    );
330→
331→    return {
332→      skipped: false,
333→      targetJid,
334→      outboundId,
335→      sendResult,
336→    };
337→  }
338→
339→  async sendReplyWithRouting({
340→    incomingJid,
341→    inboundMessageId,
342→    replyText,
343→    fromMe,
344→  }) {
345→    const inboundKey = makeInboundReplyKey(incomingJid, inboundMessageId);
346→    if (this.hasInboundReplyCompleted(inboundKey)) {
347→      this.logger.info(
348→        `Reply already completed for inId=${inboundMessageId}. Skipping duplicate send.`,
349→      );
350→      return { skipped: true, reason: "already_completed" };
351→    }
352→
353→    const meId = this.socket?.user?.id || "";
354→    const meLid = this.socket?.user?.lid || "";
355→    const routing = resolveReplyTargets({
356→      incomingJid,
357→      fromMe,
358→      meId,
359→      meLid,
360→      singleNumberMode: this.config.app.singleNumberMode,
361→      enableFallback: this.config.replyRouting.enableFallback,
362→      strategy: this.config.replyRouting.strategy,
363→    });
364→
365→    this.logger.info(
366→      `Reply routing inId=${inboundMessageId} strategy=${routing.strategy} reason=${routing.reason} primary=${routing.primary} fallbacks=[${routing.fallbacks.join(",") || "none"}].`,
367→    );
368→
369→    const targets = [routing.primary, ...routing.fallbacks].filter(Boolean);
370→    if (!targets.length) {
371→      throw new Error(
372→        `No valid reply target resolved for inId=${inboundMessageId}. incomingJid=${incomingJid}`,
373→      );
374→    }
375→    let lastError = null;
376→    let lastSuccess = null;
377→
378→    for (let i = 0; i < targets.length; i += 1) {
379→      const target = targets[i];
380→      if (this.hasInboundReplyCompleted(inboundKey)) {
381→        return {
382→          skipped: true,
383→          reason: "completed_during_send",
384→        };
385→      }
386→
387→      try {
388→        const attempt = await this.sendReplyToTarget({
389→          inboundKey,
390→          inboundMessageId,
391→          targetJid: target,
392→          replyText,
393→        });
394→        if (attempt.skipped) {
395→          continue;
396→        }
397→
398→        const hasFallback =
399→          this.config.replyRouting.enableFallback &&
400→          routing.fallbacks.length > 0 &&
401→          i === 0;
402→        let verified = true;
403→
404→        if (hasFallback) {
405→          verified = await this.waitForDeliveryEvidence(target, attempt.outboundId);
406→          this.logger.info(
407→            `Reply verify inId=${inboundMessageId} outId=${attempt.outboundId || "unknown"} target=${target} verified=${verified}.`,
408→          );
409→        }
410→
411→        lastSuccess = {
412→          ...attempt,
413→          usedFallback: i > 0,
414→          verified,
415→        };
416→
417→        if (verified || !hasFallback) {
418→          this.markInboundReplyCompleted(inboundKey);
419→          return lastSuccess;
420→        }
421→
422→        this.logger.warn(
423→          `No delivery evidence for primary target ${target} (inId=${inboundMessageId}). Trying fallback target.`,
424→        );
425→      } catch (error) {
426→        lastError = error;
427→        this.logger.error(
428→          `Reply send attempt failed inId=${inboundMessageId} target=${target}: ${error.message}`,
429→        );
430→      }
431→    }
432→
433→    if (lastSuccess) {
434→      this.markInboundReplyCompleted(inboundKey);
435→      return lastSuccess;
436→    }
437→
438→    throw lastError || new Error("Failed to send reply on all candidate targets.");
439→  }
440→
441→  rememberBotOutgoingMessage(chatJid, messageId, text) {
442→    const key = makeChatMessageKey(chatJid, messageId);
443→    this.cacheSet(
444→      this.botMessageIdCache,
445→      key,
446→      this.config.loopGuard.botMessageIdTtlMs,
447→    );
448→    const fingerprint = makeTextFingerprint(chatJid, text);
449→    this.cacheSet(
450→      this.botMessageTextCache,
451→      fingerprint,
452→      this.config.loopGuard.botMessageTextTtlMs,
453→    );
454→  }
455→
456→  shouldSkipAsDuplicate(chatJid, messageId) {
457→    const key = makeChatMessageKey(chatJid, messageId);
458→    if (this.cacheHas(this.processedMessageCache, key)) {
459→      return true;
460→    }
461→    this.cacheSet(
462→      this.processedMessageCache,
463→      key,
464→      this.config.loopGuard.processedMessageTtlMs,
465→    );
466→    return false;
467→  }
468→
469→  shouldSkipFromMeEcho(chatJid, messageId, text) {
470→    const messageKey = makeChatMessageKey(chatJid, messageId);
471→    const byId = this.cacheHas(this.botMessageIdCache, messageKey);
472→    const byText = this.cacheHas(
473→      this.botMessageTextCache,
474→      makeTextFingerprint(chatJid, text),
475→    );
476→    if (byId || byText) {
477→      this.markOutboundEchoObserved(chatJid, messageId);
478→    }
479→    return byId || byText;
480→  }
481→
482→  async handleIncomingMessage(baileysMsg) {
483→    try {
484→      if (!baileysMsg?.key?.remoteJid) return;
485→      if (baileysMsg.key.remoteJid === "status@broadcast") return;
486→
487→      const chatJid = baileysMsg.key.remoteJid;
488→      const messageId = baileysMsg.key.id || `${Date.now()}`;
489→      if (this.shouldSkipAsDuplicate(chatJid, messageId)) {
490→        this.logger.info(
491→          `Skipping duplicate event for message ${messageId} in ${chatJid}.`,
492→        );
493→        return;
494→      }
495→
496→      const normalizedMessage = unwrapMessageContainer(baileysMsg.message);
497→      const text = extractTextContent(baileysMsg.message);
498→
499→      if (baileysMsg.key.fromMe) {
500→        if (!this.config.app.singleNumberMode) {
501→          this.logger.info(
502→            `Skipping fromMe message ${messageId} from ${chatJid} because SINGLE_NUMBER_MODE=false.`,
503→          );
504→          return;
505→        }
506→        if (this.shouldSkipFromMeEcho(chatJid, messageId, text)) {
507→          this.logger.info(
508→            `Loop guard blocked bot-echo fromMe message ${messageId} in ${chatJid}.`,
509→          );
510→          return;
511→        }
512→        this.logger.info(
513→          `Accepted fromMe operator message ${messageId} in ${chatJid} (single-number mode).`,
514→        );
515→      }
516→
517→      const attachments = await this.extractAttachments(
518→        baileysMsg,
519→        normalizedMessage,
520→      );
521→
522→      this.logger.info(
523→        `Inbound message accepted from ${baileysMsg.key.remoteJid} (fromMe=${Boolean(baileysMsg.key.fromMe)} textPreview="${textPreview(text)}" attachments=${attachments.length}).`,
524→      );
525→
526→      const input = {
527→        userId: chatJid,
528→        messageId,
529→        text,
530→        attachments,
531→        timestamp: new Date(
532→          Number(baileysMsg.messageTimestamp || Math.floor(Date.now() / 1000)) *
533→            1000,
534→        ).toISOString(),
535→      };
536→
537→      const startedAt = Date.now();
538→      this.logger.info(
539→        `Agent handling started for message ${messageId} in ${chatJid}.`,
540→      );
541→      const result = await withTimeout(
542→        this.agent.handleIncoming(input),
543→        this.config.app.agentTimeoutMs,
544→        "agent.handleIncoming",
545→      );
546→      this.logger.info(
547→        `Agent handling completed for message ${messageId} in ${Date.now() - startedAt}ms.`,
548→      );
549→      if (result?.replyText) {
550→        const routed = await this.sendReplyWithRouting({
551→          incomingJid: chatJid,
552→          inboundMessageId: messageId,
553→          replyText: result.replyText,
554→          fromMe: Boolean(baileysMsg.key.fromMe),
555→        });
556→        this.logger.info(
557→          `Reply sent for message ${messageId}. outId=${routed?.outboundId || "unknown"} target=${routed?.targetJid || chatJid} usedFallback=${Boolean(routed?.usedFallback)} verified=${routed?.verified !== false}.`,
558→        );
559→      } else {
560→        this.logger.warn(
561→          `Agent returned empty reply for message ${messageId}; sending fallback guidance.`,
562→        );
563→        const fallbackText =
564→          "I could not produce a response for that message. Please rephrase your request in one sentence.";
565→        await this.sendReplyWithRouting({
566→          incomingJid: chatJid,
567→          inboundMessageId: messageId,
568→          replyText: fallbackText,
569→          fromMe: Boolean(baileysMsg.key.fromMe),
570→        });
571→      }
572→    } catch (error) {
573→      this.logger.error(`Message handling failed: ${error.message}`);
574→      try {
575→        const chatJid = baileysMsg?.key?.remoteJid;
576→        const inboundId = baileysMsg?.key?.id || `${Date.now()}`;
577→        if (!chatJid) return;
578→        const errorText =
579→          "I encountered an internal error while processing your request. Please try again.";
580→        await this.sendReplyWithRouting({
581→          incomingJid: chatJid,
582→          inboundMessageId: inboundId,
583→          replyText: errorText,
584→          fromMe: Boolean(baileysMsg?.key?.fromMe),
585→        });
586→      } catch (sendError) {
587→        this.logger.error(`Failed to send error message: ${sendError.message}`);
588→      }
589→    }
590→  }
591→
592→  async extractAttachments(baileysMsg, normalizedMessage) {
593→    const attachments = [];
594→    if (!normalizedMessage) return attachments;
595→
596→    if (normalizedMessage.imageMessage) {
597→      const buffer = await downloadMediaMessage(
598→        baileysMsg,
599→        "buffer",
600→        {},
601→        { logger: pino({ level: "silent" }) },
602→      );
603→      const imageMime = normalizedMessage.imageMessage.mimetype || "image/jpeg";
604→      const fileName = makeFileNameFromMime(
605→        baileysMsg.key.id || "image",
606→        "image",
607→        imageMime,
608→      );
609→      const targetPath = path.join(this.config.paths.inbox, fileName);
610→      await fs.writeFile(targetPath, buffer);
611→      attachments.push({
612→        type: "image",
613→        path: targetPath,
614→        mime: imageMime,
615→        originalName: fileName,
616→      });
617→    }
618→
619→    if (normalizedMessage.documentMessage) {
620→      const buffer = await downloadMediaMessage(
621→        baileysMsg,
622→        "buffer",
623→        {},
624→        { logger: pino({ level: "silent" }) },
625→      );
626→      const docMime =
627→        normalizedMessage.documentMessage.mimetype ||
628→        "application/octet-stream";
629→      const originalName =
630→        normalizedMessage.documentMessage.fileName ||
631→        makeFileNameFromMime(baileysMsg.key.id || "document", "document", docMime);
632→      const safeName = originalName.replace(/[<>:"/\\|?*\u0000-\u001F]/g, "_");
633→      const targetPath = path.join(
634→        this.config.paths.inbox,
635→        `${compactTimestamp()}_${safeName}`,
636→      );
637→      await fs.writeFile(targetPath, buffer);
638→      attachments.push({
639→        type: "document",
640→        path: targetPath,
641→        mime: docMime,
642→        originalName: originalName,
643→      });
644→    }
645→
646→    return attachments;
647→  }
648→}
