 1→import { isLidUser, jidDecode, jidEncode, jidNormalizedUser } from "@whiskeysockets/baileys";
 2→
 3→function unique(items) {
 4→  const output = [];
 5→  const seen = new Set();
 6→  for (const item of items) {
 7→    const value = String(item || "").trim();
 8→    if (!value) continue;
 9→    if (seen.has(value)) continue;
10→    seen.add(value);
11→    output.push(value);
12→  }
13→  return output;
14→}
