120→export class GradeAgent {
121→  constructor({ config, logger, tools, gradeService }) {
122→    this.config = config;
123→    this.logger = logger;
124→    this.tools = tools;
125→    this.gradeService = gradeService;
126→    this.actions = tools.createActionTools(gradeService);
127→  }
128→
129→  async inferIntentWithOllama(userId, text) {
130→    const memory = await this.gradeService.readUserMemory(userId);
131→    const historySnippet = (memory.history || [])
132→      .slice(-6)
133→      .map((item) => `${item.role}: ${item.text}`)
134→      .join("\n");
135→
136→    const extractionPrompt = [
137→      "/no_think",
138→      "Extract teacher intent from the message.",
139→      "Return strict JSON ONLY, no explanation.",
140→      '{ "intent": "add_scores|calculate_stats|generate_report|apply_curve|backup_all|import_document|help|unknown", "classFile": "optional", "studentScores":[{"student":"Name","score":90}], "mode":"optional" }',
141→      "Rules:",
142→      "- Do not invent student scores.",
143→      "- Keep classFile null if not provided.",
144→      "- studentScores must be empty unless clearly provided.",
145→      "- Reply with ONLY the JSON object, nothing else.",
146→      "",
147→      "Recent conversation:",
148→      historySnippet || "(none)",
149→      "",
150→      `Current message: ${text}`,
151→    ].join("\n");
152→
153→    const doRequest = async () => {
154→      const response = await postOllamaChat({
155→        baseUrl: this.config.ollama.baseUrl,
156→        model: this.config.ollama.model,
157→        messages: [
158→          { role: "system", content: SYSTEM_PROMPT },
159→          { role: "user", content: extractionPrompt },
160→        ],
161→        timeoutMs: this.config.ollama.requestTimeoutMs,
162→        logger: this.logger,
163→        stream: false,
164→      });
165→      return response?.data?.message?.content;
166→    };
167→
168→    const content = await pRetry(doRequest, {
169→      retries: Math.max(0, (this.config.ollama.retries || 1) - 1),
170→      factor: 2,
171→      minTimeout: 600,
172→      maxTimeout: 5000,
173→      onFailedAttempt: (error) => {
174→        this.logger.warn(`Intent extraction retry ${error.attemptNumber}: ${error.message}`);
175→      },
176→    });
177→
178→    return parseJsonLoose(content) || { intent: "unknown" };
179→  }
180→
181→  async inferIntent(userId, text) {
182→    const ruleBased = parseRuleBasedIntent(text);
183→    if (ruleBased.intent !== "unknown") {
184→      return ruleBased;
185→    }
186→    if (!text || text.trim().length < 2) {
187→      return { intent: "unknown" };
188→    }
189→    try {
190→      const ollamaIntent = await this.inferIntentWithOllama(userId, text);
191→      return {
192→        intent: ollamaIntent.intent || "unknown",
193→        classFile: ollamaIntent.classFile || null,
194→        studentScores: Array.isArray(ollamaIntent.studentScores)
195→          ? ollamaIntent.studentScores
196→          : [],
197→        mode: ollamaIntent.mode || null,
198→      };
199→    } catch (error) {
200→      this.logger.error(`Intent inference failed: ${error.message}`);
201→      return { intent: "unknown" };
202→    }
203→  }
204→
205→  async handleImageAttachment(input, imageAttachment) {
206→    const classFileHint = extractClassFileHint(input.text || "");
207→    const visionResult = await this.tools.vision.extractScoresFromImage({
208→      imagePath: imageAttachment.path,
209→      suggestedClassFile: classFileHint || "class1.xlsx",
210→    });
211→
212→    if (!visionResult.rows.length) {
213→      const warningText = visionResult.warnings.length
214→        ? `\nWarnings:\n- ${visionResult.warnings.join("\n- ")}`
215→        : "";
216→      return {
217→        replyText: `I could not extract usable scores from that image.${warningText}`,
218→      };
219→    }
220→
221→    const prepared = await this.actions.processPhoto.execute(
222→      { userId: input.userId },
223→      {
224→        classFile: visionResult.classFile,
225→        rows: visionResult.rows,
226→      },
227→    );
228→
229→    const extractedPreview = visionResult.rows
230→      .slice(0, 8)
231→      .map((row) => `- ${row.student}: ${row.score}`)
232→      .join("\n");
233→    const warnings = visionResult.warnings.length
234→      ? `\nOCR notes:\n- ${visionResult.warnings.join("\n- ")}`
235→      : "";
236→
237→    return {
238→      replyText: [
239→        "I extracted the following scores from your photo:",
240→        extractedPreview,
241→        warnings,
242→        "",
243→        prepared.replyText,
244→      ]
245→        .filter(Boolean)
246→        .join("\n"),
247→    };
248→  }
249→
250→  async handleDocumentAttachment(input, docAttachment) {
251→    await this.gradeService.setLastUploadedDocument(input.userId, {
252→      path: docAttachment.path,
253→      originalName: docAttachment.originalName || "uploaded.xlsx",
254→      mime: docAttachment.mime,
255→      receivedAt: new Date().toISOString(),
256→    });
257→
258→    const text = input.text || "";
259→    if (/import|use as/i.test(text)) {
260→      const classFileHint = extractClassFileHint(text) || docAttachment.originalName;
261→      return this.actions.importDocument.execute(
262→        { userId: input.userId },
263→        {
264→          documentPath: docAttachment.path,
265→          originalName: docAttachment.originalName,
266→          classFile: classFileHint,
267→        },
268→      );
269→    }
270→
271→    return {
272→      replyText: [
273→        `I received your file: ${docAttachment.originalName || "uploaded file"}.`,
274→        "What would you like me to do next?",
275→        "- Import it to managed grades storage",
276→        "- Calculate full stats and rankings",
277→        "- Generate a parent PDF report",
278→        "- Apply a gentle curve",
279→        "You can reply with: Import as class1.xlsx",
280→      ].join("\n"),
281→    };
282→  }
283→
284→  async handleTextIntent(input, intent) {
285→    const context = { userId: input.userId };
286→    switch (intent.intent) {
287→      case "add_scores":
288→        return this.actions.addScores.execute(context, {
289→          classFile: intent.classFile,
290→          studentScores: intent.studentScores || [],
291→        });
292→      case "calculate_stats":
293→        return this.actions.calculateStats.execute(context, {
294→          classFile: intent.classFile,
295→        });
296→      case "generate_report":
297→        return this.actions.generateReport.execute(context, {
298→          classFile: intent.classFile,
299→        });
300→      case "apply_curve":
301→        return this.actions.applyCurve.execute(context, {
302→          classFile: intent.classFile,
303→          mode: intent.mode || "gentle_bell",
304→        });
305→      case "backup_all":
306→        return this.actions.backupAll.execute(context, {});
307→      case "import_document": {
308→        const uploaded = await this.gradeService.getLastUploadedDocument(input.userId);
309→        if (!uploaded) {
310→          return {
311→            replyText:
312→              "Please send an Excel or CSV file first, then I can import it for you.",
313→          };
314→        }
315→        return this.actions.importDocument.execute(context, {
316→          documentPath: uploaded.path,
317→          originalName: uploaded.originalName,
318→          classFile: intent.classFile || uploaded.originalName,
319→        });
320→      }
321→      case "help":
322→        return { replyText: helpMessage() };
323→      default:
324→        return {
325→          replyText: [
326→            "I could not determine the exact action yet.",
327→            helpMessage(),
328→          ].join("\n\n"),
329→        };
330→    }
331→  }
332→
333→  async handleIncoming(input) {
334→    await this.gradeService.addConversation(
335→      input.userId,
336→      "user",
337→      input.text || `[attachment:${(input.attachments || []).map((a) => a.type).join(",")}]`,
338→    );
339→
340→    const confirmation = parseYesNo(input.text);
341→    if (confirmation) {
342→      const confirmationResult = await this.gradeService.handleConfirmation(
343→        { userId: input.userId },
344→        confirmation,
345→      );
346→      await this.gradeService.addConversation(
347→        input.userId,
348→        "assistant",
349→        confirmationResult.replyText,
350→      );
351→      return confirmationResult;
352→    }
353→
354→    const attachments = Array.isArray(input.attachments) ? input.attachments : [];
355→    if (attachments.length) {
356→      const image = attachments.find((a) => a.type === "image");
357→      if (image) {
358→        const imageResult = await this.handleImageAttachment(input, image);
359→        await this.gradeService.addConversation(
360→          input.userId,
361→          "assistant",
362→          imageResult.replyText,
363→        );
364→        return imageResult;
365→      }
366→      const document = attachments.find((a) => a.type === "document");
367→      if (document) {
368→        const documentResult = await this.handleDocumentAttachment(input, document);
369→        await this.gradeService.addConversation(
370→          input.userId,
371→          "assistant",
372→          documentResult.replyText,
373→        );
374→        return documentResult;
375→      }
376→    }
377→
378→    const intent = await this.inferIntent(input.userId, input.text || "");
379→    const textResult = await this.handleTextIntent(input, intent);
380→    await this.gradeService.addConversation(
381→      input.userId,
382→      "assistant",
383→      textResult.replyText,
384→    );
385→    return textResult;
386→  }
387→}
